import React, { useState, useCallback, useMemo, useRef } from 'react';
import {
  Button,
  Input,
  MoneyInput,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  type LinListToolbarActionDef,
} from '@linm-soft-org/linm-web-common-components';
import { usePurchaseApproverPermissions } from '../../../hooks/usePurchaseApproverPermissions';
import { useAppDispatch } from '../../../store/hooks';
import { purchasingService } from '../../../services/mh/purchasingService';
import type { PurchaseApproverDto } from '../../../services/mh/models';
import { phanQuyenDuyetPageLabels as labels } from '../../../constants/phanQuyenDuyetPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { formatMoneyVnd } from '../../../utils/formatters';
import { FormMode, isEditingMode, isViewMode } from '../../../components/form/FormMode';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-mh-phan-quyen-duyet';
const PAGE_ID = 'mh-phan-quyen-duyet';

const emptyApprover = (): PurchaseApproverDto => ({
  userId: '',
  userName: '',
  level: 1,
  maxAmount: 0,
  isActive: true,
});

const cloneApprovers = (rows: PurchaseApproverDto[]): PurchaseApproverDto[] =>
  rows.map(row => ({ ...row }));

const PhanQuyenDuyetPage: React.FC = () => {
  const { canWrite } = usePurchaseApproverPermissions();
  const dispatch = useAppDispatch();
  const [approvers, setApprovers] = useState<PurchaseApproverDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [formMode, setFormMode] = useState(FormMode.View);
  const snapshotRef = useRef<PurchaseApproverDto[]>([]);

  const isEditing = isEditingMode(formMode);
  const isView = isViewMode(formMode);
  const hasRows = approvers.length > 0;

  const load = useCallback(() => {
    setLoading(true);
    purchasingService.getApprovers()
      .then(data => {
        const rows = data.length ? data : [];
        setApprovers(rows);
        setFormMode(FormMode.View);
      })
      .catch(err => dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.loadError),
        type: 'error',
      }))
      .finally(() => setLoading(false));
  }, [dispatch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const updateApprover = (idx: number, patch: Partial<PurchaseApproverDto>) => {
    setApprovers(prev => prev.map((a, i) => (i === idx ? { ...a, ...patch } : a)));
  };

  const handleEdit = useCallback(() => {
    snapshotRef.current = cloneApprovers(approvers.length ? approvers : [emptyApprover()]);
    if (!approvers.length) setApprovers([emptyApprover()]);
    setFormMode(FormMode.Edit);
  }, [approvers]);

  const handleCreate = useCallback(() => {
    snapshotRef.current = [];
    setApprovers([emptyApprover()]);
    setFormMode(FormMode.Create);
  }, []);

  const handleCancel = useCallback(() => {
    const snap = snapshotRef.current;
    setApprovers(snap.length ? cloneApprovers(snap) : []);
    setFormMode(FormMode.View);
  }, []);

  const handleAddApprover = useCallback(() => {
    setApprovers(prev => [...prev, emptyApprover()]);
  }, []);

  const handleSave = useCallback(async () => {
    setSaving(true);
    try {
      const saved = await purchasingService.saveApprovers(approvers);
      setApprovers(saved.length ? saved : approvers);
      dispatchAppToast(dispatch, { message: labels.saveSuccess, type: 'success' });
      setFormMode(FormMode.View);
      load();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, labels.saveError),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  }, [approvers, dispatch, load]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  const headerHint = useMemo(() => {
    if (formMode === FormMode.Create) return labels.createHint;
    if (formMode === FormMode.Edit) return labels.editHint;
    return labels.viewHint;
  }, [formMode]);

  const activeCount = useMemo(
    () => approvers.filter(a => a.isActive).length,
    [approvers],
  );

  const maxLimit = useMemo(
    () => (approvers.length ? Math.max(...approvers.map(a => a.maxAmount), 0) : 0),
    [approvers],
  );

  const toolbarActions = useMemo((): LinListToolbarActionDef[] => {
    const left: LinListToolbarActionDef[] = [
      {
        id: 'refresh',
        placement: 'left',
        action: 'refresh',
        visible: true,
        disabled: isEditing,
        onClick: load,
        testId: `${TEST_ID}-toolbar-refresh-btn`,
      },
    ];

    if (isView) {
      const right: LinListToolbarActionDef[] = canWrite
        ? (hasRows
          ? [{
            id: 'edit',
            placement: 'right',
            action: 'edit',
            visible: true,
            onClick: handleEdit,
            testId: `${TEST_ID}-toolbar-edit-btn`,
          }]
          : [{
            id: 'create',
            placement: 'right',
            action: 'create',
            variant: 'primary',
            visible: true,
            onClick: handleCreate,
            testId: `${TEST_ID}-toolbar-add-btn`,
          }])
        : [];
      return [...left, ...right];
    }

    const editRight: LinListToolbarActionDef[] = [
      {
        id: 'add-approver',
        placement: 'right',
        label: labels.addApprover,
        variant: 'secondary',
        visible: true,
        disabled: saving,
        onClick: handleAddApprover,
        testId: `${TEST_ID}-toolbar-add-approver-btn`,
      },
      {
        id: 'cancel',
        placement: 'right',
        label: labels.cancel,
        variant: 'secondary',
        visible: true,
        disabled: saving,
        onClick: handleCancel,
        testId: `${TEST_ID}-toolbar-cancel-btn`,
      },
      {
        id: 'save',
        placement: 'right',
        visible: true,
        testId: `${TEST_ID}-toolbar-save-btn`,
        render: () => (
          <Button
            variant="primary"
            size="sm"
            loading={saving}
            disabled={saving}
            data-testid={`${TEST_ID}-save`}
            onClick={handleSave}
          >
            {labels.save}
          </Button>
        ),
      },
    ];
    return [...left, ...editRight];
  }, [
    isView,
    isEditing,
    hasRows,
    canWrite,
    load,
    handleEdit,
    handleCreate,
    handleCancel,
    handleAddApprover,
    handleSave,
    saving,
  ]);

  const listBody = !showTableLoading && !hasRows ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>{labels.empty}</div>
  ) : !showTableLoading ? (
    <>
      <div className={erp.tableWrapper} data-testid={`${TEST_ID}-table`}>
        <table className={erp.table}>
          <thead>
            <tr>
              <th>{labels.colUserId}</th>
              <th>{labels.colUserName}</th>
              <th>{labels.colLevel}</th>
              <th className={erp.colRight}>{labels.colMaxAmount}</th>
              <th>{labels.colActive}</th>
              {isEditing && <th className={erp.colActions} aria-label="Thao tác" />}
            </tr>
          </thead>
          <tbody>
            {approvers.map((a, idx) => (
              <tr key={idx} data-testid={`${TEST_ID}-row-${idx + 1}`}>
                <td>
                  {isView ? (
                    <span data-testid={`${TEST_ID}-row-${idx + 1}-userId`}>{a.userId || '—'}</span>
                  ) : (
                    <Input
                      value={a.userId}
                      onChange={e => updateApprover(idx, { userId: e.target.value })}
                      size="small"
                      data-testid={`${TEST_ID}-row-${idx + 1}-userId`}
                    />
                  )}
                </td>
                <td>
                  {isView ? (
                    <span data-testid={`${TEST_ID}-row-${idx + 1}-userName`}>{a.userName || '—'}</span>
                  ) : (
                    <Input
                      value={a.userName}
                      onChange={e => updateApprover(idx, { userName: e.target.value })}
                      size="small"
                      data-testid={`${TEST_ID}-row-${idx + 1}-userName`}
                    />
                  )}
                </td>
                <td>
                  {isView ? (
                    <span data-testid={`${TEST_ID}-row-${idx + 1}-level`}>{a.level}</span>
                  ) : (
                    <Input
                      type="number"
                      value={String(a.level)}
                      onChange={e => updateApprover(idx, { level: Math.max(1, Number(e.target.value) || 1) })}
                      size="small"
                      data-testid={`${TEST_ID}-row-${idx + 1}-level`}
                    />
                  )}
                </td>
                <td className={erp.colRight}>
                  {isView ? (
                    <span data-testid={`${TEST_ID}-row-${idx + 1}-max`}>
                      {formatMoneyVnd(a.maxAmount)}
                    </span>
                  ) : (
                    <MoneyInput
                      value={a.maxAmount}
                      onChange={val => updateApprover(idx, { maxAmount: val })}
                      data-testid={`${TEST_ID}-row-${idx + 1}-max`}
                    />
                  )}
                </td>
                <td>
                  {isView ? (
                    <span data-testid={`${TEST_ID}-row-${idx + 1}-active`}>
                      {a.isActive ? labels.activeYes : labels.activeNo}
                    </span>
                  ) : (
                    <input
                      type="checkbox"
                      checked={a.isActive}
                      onChange={e => updateApprover(idx, { isActive: e.target.checked })}
                      data-testid={`${TEST_ID}-row-${idx + 1}-active`}
                    />
                  )}
                </td>
                {isEditing && (
                  <td className={erp.colActions}>
                    <button
                      type="button"
                      className={erp.actionBtn}
                      onClick={() => setApprovers(p => p.filter((_, i) => i !== idx))}
                      disabled={approvers.length <= 1}
                      title="Xóa"
                      data-testid={`${TEST_ID}-row-${idx + 1}-delete`}
                    >
                      <i className="fas fa-trash" />
                    </button>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <div className={erp.footer} data-testid={`${TEST_ID}-footer`}>
        <span className={erp.totalCount}>
          {labels.footerSummary(activeCount, maxLimit)}
        </span>
      </div>
    </>
  ) : null;

  return (
    <div
      className={erp.catalogListRoot}
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
      data-form-mode={formMode}
    >
      <LinPageLayout
        kind="catalog"
        filterBarLayout="compact"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={erp.catalogListPage}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-user-shield',
          pageId: PAGE_ID,
          hint: headerHint,
        }}
        toolbarProps={{
          testIdPrefix: TEST_ID,
          profile: 'catalog',
          actions: toolbarActions,
        }}
        listTitle={labels.listTitle}
        showTableLoading={showTableLoading}
        skeletonRows={4}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default PhanQuyenDuyetPage;
